/* Genre 6A (Phase 2): missing-item loot cleanup with safety caps */
USE `world`;
SELECT DATABASE() AS current_database;

SET @APPLY_FIX := 1;
SET @MAX_DELETE_PER_TABLE := 5000;
SET @MAX_DELETE_TOTAL := 20000;
SET @FORCE_DELETE := 0;

SET @OLD_SQL_SAFE_UPDATES := @@sql_safe_updates;
SET @OLD_FOREIGN_KEY_CHECKS := @@foreign_key_checks;
SET @OLD_UNIQUE_CHECKS := @@unique_checks;
SET @OLD_AUTOCOMMIT := @@autocommit;
SET @@sql_safe_updates := 0;
SET @@foreign_key_checks := 0;
SET @@unique_checks := 0;
SET @@autocommit := 0;
START TRANSACTION;

DROP TEMPORARY TABLE IF EXISTS tmp_loot_missing_summary;
CREATE TEMPORARY TABLE tmp_loot_missing_summary (
  table_name VARCHAR(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  missing_before BIGINT NOT NULL DEFAULT 0,
  sample_shown INT NOT NULL DEFAULT 0,
  will_delete BIGINT NOT NULL DEFAULT 0,
  deleted_rows BIGINT NOT NULL DEFAULT 0,
  missing_after BIGINT NOT NULL DEFAULT 0,
  note VARCHAR(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '',
  PRIMARY KEY (table_name)
) ENGINE=InnoDB;

DROP TEMPORARY TABLE IF EXISTS tmp_loot_targets;
CREATE TEMPORARY TABLE tmp_loot_targets (
  table_name VARCHAR(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  item_col VARCHAR(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  entry_col VARCHAR(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL,
  PRIMARY KEY (table_name)
) ENGINE=InnoDB;

SET @has_world_item_template := (SELECT COUNT(*) FROM information_schema.tables WHERE table_schema = DATABASE() AND table_name = 'item_template');
SET @has_world_item_sparse := (SELECT COUNT(*) FROM information_schema.tables WHERE table_schema = DATABASE() AND table_name = 'item_sparse');
SET @has_hotfixes_schema := (SELECT COUNT(*) FROM information_schema.schemata WHERE schema_name = 'hotfixes');
SET @has_hotfix_item_sparse := IF(@has_hotfixes_schema > 0, (SELECT COUNT(*) FROM information_schema.tables WHERE table_schema = 'hotfixes' AND table_name = 'item_sparse'), 0);
SET @has_hotfix_item := IF(@has_hotfixes_schema > 0, (SELECT COUNT(*) FROM information_schema.tables WHERE table_schema = 'hotfixes' AND table_name = 'item'), 0);

SET @pk_world_item_template := IF(@has_world_item_template > 0, (SELECT column_name FROM information_schema.columns WHERE table_schema = DATABASE() AND table_name = 'item_template' AND column_name IN ('entry','Entry','ID','id') ORDER BY FIELD(column_name,'entry','Entry','ID','id') LIMIT 1), NULL);
SET @pk_world_item_sparse := IF(@has_world_item_sparse > 0, (SELECT column_name FROM information_schema.columns WHERE table_schema = DATABASE() AND table_name = 'item_sparse' AND column_name IN ('ID','id','entry','Entry') ORDER BY FIELD(column_name,'ID','id','entry','Entry') LIMIT 1), NULL);
SET @pk_hotfix_item_sparse := IF(@has_hotfix_item_sparse > 0, (SELECT column_name FROM information_schema.columns WHERE table_schema = 'hotfixes' AND table_name = 'item_sparse' AND column_name IN ('ID','id','entry','Entry') ORDER BY FIELD(column_name,'ID','id','entry','Entry') LIMIT 1), NULL);
SET @pk_hotfix_item := IF(@has_hotfix_item > 0, (SELECT column_name FROM information_schema.columns WHERE table_schema = 'hotfixes' AND table_name = 'item' AND column_name IN ('ID','id','entry','Entry') ORDER BY FIELD(column_name,'ID','id','entry','Entry') LIMIT 1), NULL);

SET @usable_world_item_template := IF(@has_world_item_template > 0 AND @pk_world_item_template IS NOT NULL, 1, 0);
SET @usable_world_item_sparse := IF(@has_world_item_sparse > 0 AND @pk_world_item_sparse IS NOT NULL, 1, 0);
SET @usable_hotfix_item_sparse := IF(@has_hotfix_item_sparse > 0 AND @pk_hotfix_item_sparse IS NOT NULL, 1, 0);
SET @usable_hotfix_item := IF(@has_hotfix_item > 0 AND @pk_hotfix_item IS NOT NULL, 1, 0);
SET @has_any_item_source := IF((@usable_world_item_template + @usable_world_item_sparse + @usable_hotfix_item_sparse + @usable_hotfix_item) > 0, 1, 0);

SET @tbl := 'creature_loot_template';
SET @tbl_exists := (SELECT COUNT(*) FROM information_schema.tables WHERE table_schema = DATABASE() AND table_name = @tbl);
SET @item_col := IF(@tbl_exists > 0, (SELECT column_name FROM information_schema.columns WHERE table_schema = DATABASE() AND table_name = @tbl AND column_name IN ('Item','item','itemid','ItemID') ORDER BY FIELD(column_name,'Item','item','itemid','ItemID') LIMIT 1), NULL);
SET @entry_col := IF(@tbl_exists > 0, (SELECT column_name FROM information_schema.columns WHERE table_schema = DATABASE() AND table_name = @tbl AND column_name IN ('Entry','entry') ORDER BY FIELD(column_name,'Entry','entry') LIMIT 1), NULL);
SET @chance_col := IF(@tbl_exists > 0, (SELECT column_name FROM information_schema.columns WHERE table_schema = DATABASE() AND table_name = @tbl AND column_name IN ('ChanceOrQuestChance','chance') ORDER BY FIELD(column_name,'ChanceOrQuestChance','chance') LIMIT 1), NULL);
SET @group_col := IF(@tbl_exists > 0, (SELECT column_name FROM information_schema.columns WHERE table_schema = DATABASE() AND table_name = @tbl AND column_name IN ('groupid','GroupId') ORDER BY FIELD(column_name,'groupid','GroupId') LIMIT 1), NULL);
SET @has_reference := IF(@tbl_exists > 0, (SELECT COUNT(*) FROM information_schema.columns WHERE table_schema = DATABASE() AND table_name = @tbl AND column_name = 'Reference'), 0);
SET @can_process := IF(@tbl_exists > 0 AND @item_col IS NOT NULL AND @has_any_item_source = 1, 1, 0);
SET @join_sql := CONCAT(IF(@usable_world_item_template=1, CONCAT(' LEFT JOIN `',DATABASE(),'`.`item_template` it ON it.`',@pk_world_item_template,'` = CAST(l.`',@item_col,'` AS UNSIGNED) '), ''), IF(@usable_world_item_sparse=1, CONCAT(' LEFT JOIN `',DATABASE(),'`.`item_sparse` isw ON isw.`',@pk_world_item_sparse,'` = CAST(l.`',@item_col,'` AS UNSIGNED) '), ''), IF(@usable_hotfix_item_sparse=1, CONCAT(' LEFT JOIN `hotfixes`.`item_sparse` hs ON hs.`',@pk_hotfix_item_sparse,'` = CAST(l.`',@item_col,'` AS UNSIGNED) '), ''), IF(@usable_hotfix_item=1, CONCAT(' LEFT JOIN `hotfixes`.`item` hi ON hi.`',@pk_hotfix_item,'` = CAST(l.`',@item_col,'` AS UNSIGNED) '), ''));
SET @null_sql := CONCAT_WS(' AND ', IF(@usable_world_item_template=1, CONCAT('it.`',@pk_world_item_template,'` IS NULL'), NULL), IF(@usable_world_item_sparse=1, CONCAT('isw.`',@pk_world_item_sparse,'` IS NULL'), NULL), IF(@usable_hotfix_item_sparse=1, CONCAT('hs.`',@pk_hotfix_item_sparse,'` IS NULL'), NULL), IF(@usable_hotfix_item=1, CONCAT('hi.`',@pk_hotfix_item,'` IS NULL'), NULL));
SET @sql_count := IF(@can_process=1, CONCAT('SELECT COUNT(*) INTO @missing_before FROM `',@tbl,'` l ',@join_sql,' WHERE CAST(l.`',@item_col,'` AS SIGNED) > 0 AND ',@null_sql), 'SELECT 0 INTO @missing_before');
PREPARE stmt_count FROM @sql_count;
EXECUTE stmt_count;
DEALLOCATE PREPARE stmt_count;
SET @sample_cols := CONCAT(IF(@entry_col IS NOT NULL, CONCAT('l.`',@entry_col,'` AS `entry`'), 'NULL AS `entry`'), ', l.`',@item_col,'` AS `item`', IF(@chance_col IS NOT NULL, CONCAT(', l.`',@chance_col,'` AS `chance`'), ', NULL AS `chance`'), IF(@has_reference > 0, ', l.`Reference` AS `Reference`', ', NULL AS `Reference`'), IF(@group_col IS NOT NULL, CONCAT(', l.`',@group_col,'` AS `groupid`'), ', NULL AS `groupid`'));
SET @sql_sample := IF(@can_process=1 AND @missing_before>0, CONCAT('SELECT CAST(',QUOTE(@tbl),' AS CHAR(128)) AS `table_name`, ',@sample_cols,' FROM `',@tbl,'` l ',@join_sql,' WHERE CAST(l.`',@item_col,'` AS SIGNED) > 0 AND ',@null_sql,' LIMIT 25'), CONCAT('SELECT CAST(',QUOTE(@tbl),' AS CHAR(128)) AS `table_name`, NULL AS `entry`, NULL AS `item`, NULL AS `chance`, NULL AS `Reference`, NULL AS `groupid` LIMIT 0'));
PREPARE stmt_sample FROM @sql_sample;
EXECUTE stmt_sample;
DEALLOCATE PREPARE stmt_sample;
SET @sample_shown := IF(@missing_before > 25, 25, @missing_before);
SET @note := CASE WHEN @tbl_exists = 0 THEN 'SKIP: table missing' WHEN @item_col IS NULL THEN 'SKIP: item column missing' WHEN @has_any_item_source = 0 THEN 'SKIP: no item source tables found' ELSE 'READY' END;
INSERT INTO tmp_loot_missing_summary(table_name,missing_before,sample_shown,will_delete,deleted_rows,missing_after,note) VALUES(@tbl,@missing_before,@sample_shown,@missing_before,0,@missing_before,@note);
